arguments.file_text:
@if (Products is null || !Products.Any())
{
    <div class="empty-results" style="text-align:center; padding:3rem; color:#6c757d;">
        <p>No products found matching your criteria.</p>
    </div>
}
else
{
    <div class="product-grid" style="display:grid; grid-template-columns:repeat(auto-fill, minmax(250px, 1fr)); gap:1.5rem;">
        @foreach (var product in Products)
        {
            <ProductCard Product="product" OnSelected="OnProductSelected" OnAddToCart="OnAddToCart" />
        }
    </div>
}

@code {
    [Parameter, EditorRequired]
    public List<Product> Products { get; set; } = new();

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }
}

@{
    var totalPages = (int)Math.Ceiling((double)TotalCount / PageSize);
}

@if (totalPages > 1)
{
    <nav class="catalog-pagination" style="display:flex; justify-content:center; gap:0.25rem; margin-top:1.5rem; flex-wrap:wrap;">
        <button disabled="@(Page <= 1)" @onclick="() => GoToPage(Page - 1)"
                style="padding:0.4rem 0.8rem; border:1px solid #ddd; border-radius:4px; background:white; cursor:@(Page <= 1 ? "not-allowed" : "pointer");">
            Previous
        </button>

        @for (int i = 1; i <= totalPages; i++)
        {
            var pageNum = i;
            <button @onclick="() => GoToPage(pageNum)"
                    style="padding:0.4rem 0.8rem; border:1px solid #ddd; border-radius:4px; background:@(pageNum == Page ? "#0d6efd" : "white"); color:@(pageNum == Page ? "white" : "black"); cursor:pointer;">
                @pageNum
            </button>
        }

        <button disabled="@(Page >= totalPages)" @onclick="() => GoToPage(Page + 1)"
                style="padding:0.4rem 0.8rem; border:1px solid #ddd; border-radius:4px; background:white; cursor:@(Page >= totalPages ? "not-allowed" : "pointer");">
            Next
        </button>
    </nav>
}

@code {
    [Parameter]
    public int Page { get; set; }

    [Parameter]
    public int TotalCount { get; set; }

    [Parameter]
    public int PageSize { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        await OnPageChanged.InvokeAsync(page);
    }
}

@page "/catalog"
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="error-message" style="background:#f8d7da; color:#842029; padding:1rem; border-radius:4px; margin-bottom:1rem;">
        <strong>Error:</strong> @_error
        <button @onclick="LoadProducts" style="margin-left:1rem; padding:0.3rem 0.6rem;">Retry</button>
    </div>
}

<div class="catalog-layout" style="display:flex; gap:2rem;">
    <aside style="flex:0 0 25%; min-width:200px;">
        <CatalogFilters Categories="_categories" OnFilterApplied="HandleFilterApplied" OnFilterCleared="HandleFilterCleared" />
    </aside>

    <main style="flex:1;">
        <CatalogToolbar SortBy="@_sortBy" TotalCount="_totalCount" Page="_page" PageSize="PageSize" OnSortChanged="HandleSortChanged" />

        @if (_loading)
        {
            <div class="loading-indicator" style="text-align:center; padding:3rem; color:#6c757d;">
                <p>Loading products...</p>
            </div>
        }
        else
        {
            <ProductGrid Products="_products" OnProductSelected="HandleProductSelected" OnAddToCart="HandleAddToCart" />
            <CatalogPagination Page="_page" TotalCount="_totalCount" PageSize="PageSize" OnPageChanged="HandlePageChanged" />
        }
    </main>
</div>

@code {
    private const int PageSize = 12;

    private List<Product> _products = new();
    private List<string>? _categories;
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _page = 1;
    private int _totalCount;
    private bool _loading = true;
    private string? _error;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _categories = await ProductService.GetCategoriesAsync();
            await LoadProducts();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
            _loading = false;
        }
    }

    private async Task LoadProducts()
    {
        _loading = true;
        _error = null;
        StateHasChanged();

        try
        {
            var result = await ProductService.SearchAsync(_filter, _sortBy, _page, PageSize);
            _products = result.Items;
            _totalCount = result.TotalCount;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _page = 1;
        await LoadProducts();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _page = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _page = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        _page = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private async Task HandleAddToCart(Product product)
    {
        await OnAddToCart.InvokeAsync(product);
    }
}

