{"path": "/tmp/sv-b71ece83489d46dcbf109d67f1b70d72/Components/Pages/Catalog/ProductCard.razor", "file_text": "<div class="product-card" @onclick="HandleCardClick" style="border:1px solid #ddd; border-radius:8px; padding:1rem; cursor:pointer; display:flex; flex-direction:column; gap:0.5rem;">
    <div class="product-image-placeholder" style="background:#f0f0f0; height:150px; display:flex; align-items:center; justify-content:center; border-radius:4px;">
        <span>@Product.Name</span>
    </div>
    <h4 style="margin:0;">@Product.Name</h4>
    <span class="product-price" style="font-weight:bold; font-size:1.1rem;">@Product.Price.ToString("C")</span>
    <span class="product-rating">@GetStarRating()</span>
    @if (!Product.InStock)
    {
        <span class="out-of-stock-badge" style="background:#dc3545; color:white; padding:0.2rem 0.5rem; border-radius:4px; font-size:0.8rem; width:fit-content;">Out of Stock</span>
    }
    <button class="add-to-cart-btn" disabled="@(!Product.InStock)" @onclick="HandleAddToCart" @onclick:stopPropagation="true"
            style="margin-top:auto; padding:0.5rem; border:none; border-radius:4px; background:@(Product.InStock ? "#0d6efd" : "#6c757d"); color:white; cursor:@(Product.InStock ? "pointer" : "not-allowed");">
        Add to Cart
    </button>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
        {
            await OnAddToCart.InvokeAsync(Product);
        }
    }

    private string GetStarRating()
    {
        int filled = (int)Math.Round(Product.Rating);
        int empty = 5 - filled;
        return new string('★', filled) + new string('☆', empty);
    }
}
"}

