+<div class="catalog-filters" style="display:flex; flex-direction:column; gap:1rem;">
+    <h3>Filters</h3>
+
+    <fieldset style="border:none; padding:0;">
+        <legend style="font-weight:bold; margin-bottom:0.5rem;">Categories</legend>
+        @if (Categories is not null)
+        {
+            @foreach (var category in Categories)
+            {
+                <label style="display:block; margin-bottom:0.25rem;">
+                    <input type="checkbox" checked="@IsChecked(category)" @onchange="e => ToggleCategory(category, (bool)e.Value!)" />
+                    @category
+                </label>
+            }
+        }
+    </fieldset>
+
+    <fieldset style="border:none; padding:0;">
+        <legend style="font-weight:bold; margin-bottom:0.5rem;">Price Range</legend>
+        <div style="display:flex; gap:0.5rem; align-items:center;">
+            <input type="number" placeholder="Min" value="@_minPrice" @onchange="e => _minPrice = ParseDecimal(e.Value)"
+                   style="width:80px; padding:0.3rem;" />
+            <span>–</span>
+            <input type="number" placeholder="Max" value="@_maxPrice" @onchange="e => _maxPrice = ParseDecimal(e.Value)"
+                   style="width:80px; padding:0.3rem;" />
+        </div>
+    </fieldset>
+
+    <label style="display:flex; align-items:center; gap:0.5rem;">
+        <input type="checkbox" @bind="_inStockOnly" />
+        In Stock Only
+    </label>
+
+    <div style="display:flex; flex-direction:column; gap:0.5rem;">
+        <button @onclick="ApplyFilters" style="padding:0.5rem; background:#0d6efd; color:white; border:none; border-radius:4px; cursor:pointer;">
+            Apply Filters
+        </button>
+        <button @onclick="ClearFilters" style="padding:0.5rem; background:#6c757d; color:white; border:none; border-radius:4px; cursor:pointer;">
+            Clear Filters
+        </button>
+    </div>
+</div>
+
+@code {
+    [Parameter]
+    public List<string>? Categories { get; set; }
+
+    [Parameter]
+    public EventCallback<ProductFilter> OnFilterApplied { get; set; }
+
+    [Parameter]
+    public EventCallback OnFilterCleared { get; set; }
+
+    private List<string> _selectedCategories = new();
+    private decimal? _minPrice;
+    private decimal? _maxPrice;
+    private bool _inStockOnly;
+
+    private bool IsChecked(string category) => _selectedCategories.Contains(category);
+
+    private void ToggleCategory(string category, bool isChecked)
+    {
+        if (isChecked && !_selectedCategories.Contains(category))
+            _selectedCategories.Add(category);
+        else if (!isChecked)
+            _selectedCategories.Remove(category);
+    }
+
+    private async Task ApplyFilters()
+    {
+        var filter = new ProductFilter(
+            Categories: _selectedCategories.Any() ? _selectedCategories.ToList() : null,
+            MinPrice: _minPrice,
+            MaxPrice: _maxPrice,
+            InStockOnly: _inStockOnly
+        );
+        await OnFilterApplied.InvokeAsync(filter);
+    }
+
+    private async Task ClearFilters()
+    {
+        _selectedCategories.Clear();
+        _minPrice = null;
+        _maxPrice = null;
+        _inStockOnly = false;
+        await OnFilterCleared.InvokeAsync();
+    }
+
+    private static decimal? ParseDecimal(object? value)
+    {
+        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
+            return null;
+        return decimal.TryParse(value.ToString(), out var result) ? result : null;
+    }
+}
