+            <button @onclick="() => GoToPage(pageNum)"
+                    style="padding:0.4rem 0.8rem; border:1px solid #ddd; border-radius:4px; background:@(pageNum == Page ? "#0d6efd" : "white"); color:@(pageNum == Page ? "white" : "black"); cursor:pointer;">
+                @pageNum
+            </button>
+        }
+
+        <button disabled="@(Page >= totalPages)" @onclick="() => GoToPage(Page + 1)"
+                style="padding:0.4rem 0.8rem; border:1px solid #ddd; border-radius:4px; background:white; cursor:@(Page >= totalPages ? "not-allowed" : "pointer");">
+            Next
+        </button>
+    </nav>
+}
+
+@code {
+    [Parameter]
+    public int Page { get; set; }
+
+    [Parameter]
+    public int TotalCount { get; set; }
+
+    [Parameter]
+    public int PageSize { get; set; }
+
+    [Parameter]
+    public EventCallback<int> OnPageChanged { get; set; }
+
+    private async Task GoToPage(int page)
+    {
+        await OnPageChanged.InvokeAsync(page);
+    }
+}
+

